import React from 'react';
import { InspectorLayout } from '../ui/InspectorLayout';
import { useInspector } from '../../hooks/useInspector';
import { Asset, UserProfile, Supplier, BusinessProcess } from '../../types';
import { AssetFormData } from '../../schemas/assetSchema';
import { AssetForm } from './AssetForm';
import { RelationshipGraph } from '../RelationshipGraph';
import { AssetAIAssistant } from './AssetAIAssistant';
import { DiscussionPanel } from '../collaboration/DiscussionPanel';
import { AssetInspectorSecurity } from './inspector/AssetInspectorSecurity';
import { AssetInspectorLifecycle } from './inspector/AssetInspectorLifecycle';
import { AssetInspectorCompliance } from './inspector/AssetInspectorCompliance';
import { AssetInspectorProjects } from './inspector/AssetInspectorProjects';
import { AssetInspectorAudits } from './inspector/AssetInspectorAudits';
import { AssetInspectorDocuments } from './inspector/AssetInspectorDocuments';
import { AssetInspectorHistory } from './inspector/AssetInspectorHistory';
import { AgentDownloadModal } from './AgentDownloadModal';
import { useAssetDetails } from '../../hooks/assets/useAssetDetails';
import { useAssetSecurity } from '../../hooks/assets/useAssetSecurity';
import { useStore } from '../../store';
import { canDeleteResource } from '../../utils/permissions';
import { Trash2 } from '../ui/Icons';
import {
    ShieldAlert,
    FolderKanban, CheckSquare,
    FileText, History, Plus, Server
} from '../ui/Icons';
import { Tooltip as CustomTooltip } from '../ui/Tooltip';
import { useNavigate } from 'react-router-dom';
import { LayoutDashboard, RefreshCw, Shield, Network, BrainCircuit, MessageSquare } from '../ui/Icons';
import { getUserAvatarUrl } from '../../utils/avatarUtils';

interface AssetInspectorProps {
    isOpen: boolean;
    onClose: () => void;
    selectedAsset?: Asset | null;
    onUpdate: (id: string, data: AssetFormData) => Promise<boolean | string>;
    onCreate: (data: AssetFormData) => Promise<boolean | string>;
    users: UserProfile[];
    suppliers: Supplier[];
    processes: BusinessProcess[];
    canEdit: boolean;
    onDelete: (id: string, name: string) => void;
}

export const AssetInspector: React.FC<AssetInspectorProps> = ({
    isOpen,
    onClose,
    selectedAsset,
    onUpdate,
    onCreate,
    users,
    suppliers,
    processes,
    canEdit,
    onDelete
}) => {
    const { user, t } = useStore();
    const canDelete = React.useMemo(() => {
        if (!user) return false;
        return canDeleteResource(user, 'Asset');
    }, [user]);

    const handleDelete = () => {
        if (selectedAsset && onDelete) {
            onDelete(selectedAsset.id, selectedAsset.name);
        }
    };

    const navigate = useNavigate();

    // Memoize tabs configuration
    const tabs = React.useMemo(() => {
        const baseTabs = [{ id: 'details', label: 'Détails', icon: LayoutDashboard }];
        if (!selectedAsset) return baseTabs;

        return [
            ...baseTabs,
            { id: 'lifecycle', label: 'Cycle de Vie', icon: RefreshCw },
            { id: 'security', label: 'Sécurité', icon: ShieldAlert },
            { id: 'compliance', label: 'Conformité', icon: Shield },
            { id: 'projects', label: 'Projets', icon: FolderKanban },
            { id: 'audits', label: 'Audits', icon: CheckSquare },
            { id: 'documents', label: 'Documents', icon: FileText },
            { id: 'history', label: 'Historique', icon: History },
            { id: 'graph', label: 'Graphe', icon: Network },
            { id: 'intelligence', label: 'Intelligence', icon: BrainCircuit },
            { id: 'comments', label: 'Discussion', icon: MessageSquare }
        ];
    }, [selectedAsset]);

    // Agent Download Modal State
    const [showAgentModal, setShowAgentModal] = React.useState(false);
    const [createdAssetName, setCreatedAssetName] = React.useState<string>('');
    const [isFormDirty, setIsFormDirty] = React.useState(false);
    const [isSubmitting, setIsSubmitting] = React.useState(false);

    // Use standardized Inspector hook
    const {
        activeTab,
        setActiveTab,
        handleUpdate: handleHookUpdate,
        handleCreate: handleHookCreate
    } = useInspector({
        entity: selectedAsset || null,
        tabs,
        moduleName: 'Asset',
        actions: {
            onUpdate: async (id, data) => {
                setIsSubmitting(true);
                try {
                    const result = await onUpdate(id, data as AssetFormData);
                    if (result) setIsFormDirty(false);
                    return result;
                } finally {
                    setIsSubmitting(false);
                }
            },
            onCreate: async (data) => {
                setIsSubmitting(true);
                const formData = data as AssetFormData;
                try {
                    const result = await onCreate(formData);

                    if (result === true || typeof result === 'string') {
                        setIsFormDirty(false);
                        // Check if IT Asset to propose agent
                        // Check if IT Asset to propose agent
                        if (formData.type === 'Matériel') {
                            setCreatedAssetName(formData.name);
                            setShowAgentModal(true);
                            // Do NOT close inspector immediately to allow modal to show
                            // Inspector will be closed when user dismisses modal or downloads
                        } else {
                            onClose();
                        }
                    }
                    return result;
                } finally {
                    setIsSubmitting(false);
                }
            },
            onDelete: async (id, name) => onDelete(id, name)
        },
        getEntityName: (asset) => asset.name
    });

    const handleDownloadAgent = () => {
        // Now handled inside the modal for simulation, but we ensure state is cleared
        setShowAgentModal(false);
        onClose();
    };

    const handleCloseAgentModal = () => {
        setShowAgentModal(false);
        onClose();
    };

    const {
        maintenanceRecords,
        linkedRisks,
        linkedIncidents,
        linkedProjects,
        linkedAudits,
        linkedDocuments,
        linkedControls,
        addMaintenance
    } = useAssetDetails(selectedAsset || null);

    const {
        scanning,
        shodanResult,
        vulnerabilities,
        scanShodan,
        checkCVEs,
        createRiskFromVuln
    } = useAssetSecurity(selectedAsset || null);

    // Optimized subtitle data
    const ownerInfo = React.useMemo(() => {
        if (!selectedAsset) return null;
        const ownerUser = users?.find(u => u.displayName === selectedAsset.owner || u.email === selectedAsset.owner);
        return {
            avatar: getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role),
            name: selectedAsset.owner
        };
    }, [selectedAsset, users]);

    // Tabs defined above for both hook and render


    return (
        <InspectorLayout
            isOpen={isOpen}
            onClose={onClose}
            title={selectedAsset ? selectedAsset.name : "Nouvel Actif"}
            subtitle={
                selectedAsset && ownerInfo ? (
                    <div className="flex items-center gap-2 mt-1">
                        <span>{selectedAsset.type}</span>
                        <span className="text-muted-foreground">•</span>
                        <div className="flex items-center gap-1.5">
                            <img
                                src={ownerInfo.avatar}
                                alt=""
                                className="w-4 h-4 rounded-full object-cover bg-muted/30"
                                onError={(e) => {
                                    const target = e.target as HTMLImageElement;
                                    target.src = getUserAvatarUrl(null, 'user');
                                }}
                            />
                            <span>{ownerInfo.name}</span>
                        </div>
                    </div>
                ) : "Ajouter un nouvel actif à l'inventaire"
            }
            icon={selectedAsset ? Server : Plus}
            statusBadge={selectedAsset ? (
                <div className="flex gap-2 items-center">
                    <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase tracking-wider ${selectedAsset.lifecycleStatus === 'En service' ? 'bg-success/10 text-success' : 'bg-muted text-muted-foreground'}`}>
                        {selectedAsset.lifecycleStatus || 'Neuf'}
                    </span>
                    {canDelete && selectedAsset && (
                        <CustomTooltip content={t('assets.deleteAssetTooltip')}>
                            <button
                                onClick={(e) => { e.stopPropagation(); handleDelete(); }}
                                className="p-1.5 text-muted-foreground hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                            >
                                <Trash2 className="h-4 w-4" />
                            </button>
                        </CustomTooltip>
                    )}
                </div>
            ) : null}
            tabs={tabs}
            activeTab={activeTab}
            onTabChange={setActiveTab}
            hasUnsavedChanges={isFormDirty}
        >

            <AgentDownloadModal
                isOpen={showAgentModal}
                onClose={handleCloseAgentModal}
                onDownload={handleDownloadAgent}
                assetName={createdAssetName}
            />

            <div className="space-y-8 max-w-7xl mx-auto">
                {activeTab === 'details' && (
                    <div className="space-y-6 sm:space-y-8">
                        <AssetForm
                            initialData={selectedAsset || undefined}
                            onSubmit={async (data) => {
                                if (selectedAsset) {
                                    await handleHookUpdate(data);
                                } else {
                                    await handleHookCreate(data);
                                }
                            }}
                            usersList={users}
                            suppliers={suppliers}
                            isEditing={!!selectedAsset}
                            onCancel={onClose}
                            readOnly={!canEdit}
                            onDirtyChange={setIsFormDirty}
                            isLoading={isSubmitting}
                        />

                    </div>
                )}

                {activeTab === 'lifecycle' && selectedAsset && (
                    <AssetInspectorLifecycle
                        selectedAsset={selectedAsset}
                        maintenanceRecords={maintenanceRecords}
                        addMaintenance={addMaintenance}
                        canEdit={canEdit}
                    />
                )}

                {activeTab === 'security' && selectedAsset && (
                    <AssetInspectorSecurity
                        selectedAsset={selectedAsset}
                        scanning={scanning}
                        shodanResult={shodanResult}
                        vulnerabilities={vulnerabilities}
                        linkedRisks={linkedRisks}
                        linkedIncidents={linkedIncidents}
                        scanShodan={scanShodan}
                        checkCVEs={checkCVEs}
                        createRiskFromVuln={createRiskFromVuln}
                        navigate={navigate}
                    />
                )}

                {activeTab === 'compliance' && selectedAsset && (
                    <AssetInspectorCompliance
                        selectedAsset={selectedAsset}
                        linkedControls={linkedControls}
                        processes={processes}
                    />
                )}

                {activeTab === 'projects' && selectedAsset && (
                    <AssetInspectorProjects
                        selectedAsset={selectedAsset}
                        linkedProjects={linkedProjects}
                    />
                )}

                {activeTab === 'audits' && selectedAsset && (
                    <AssetInspectorAudits
                        linkedAudits={linkedAudits}
                    />
                )}

                {activeTab === 'documents' && selectedAsset && (
                    <AssetInspectorDocuments
                        linkedDocuments={linkedDocuments}
                    />
                )}

                {activeTab === 'history' && selectedAsset && (
                    <AssetInspectorHistory
                        selectedAsset={selectedAsset}
                    />
                )}

                {activeTab === 'graph' && selectedAsset && (
                    <div className="h-[500px]">
                        <RelationshipGraph rootId={selectedAsset.id} rootType="Asset" />
                    </div>
                )}

                {activeTab === 'intelligence' && selectedAsset && (
                    <div className="h-full overflow-y-auto p-6">
                        <AssetAIAssistant
                            asset={selectedAsset}
                            onUpdate={(updates) => handleHookUpdate(updates)}
                        />
                    </div>
                )}

                {activeTab === 'comments' && selectedAsset && (
                    <div className="h-full">
                        <DiscussionPanel
                            collectionName="assets"
                            documentId={selectedAsset.id}
                            title={`Discussion - ${selectedAsset.name}`}
                            enableSearch={true}
                            enableFilters={true}
                            enableExport={true}
                            enableNotifications={true}
                        />
                    </div>
                )}
            </div>
        </InspectorLayout>
    );
};

import React, { useMemo } from 'react';
import { Tooltip } from '../ui/Tooltip';
import { Asset, Criticality, UserProfile } from '../../types';
import { getUserAvatarUrl } from '../../utils/avatarUtils';
import { DataTable } from '../ui/DataTable';
import { Server, Edit, Trash2, Tag, Copy, HardDrive, Cpu, Database, Activity, Users } from '../ui/Icons';
import { CardSkeleton } from '../ui/Skeleton';
import { EmptyState } from '../ui/EmptyState';
import { RowActionsMenu, RowActionItem } from '../ui/RowActionsMenu';
import { canDeleteResource } from '../../utils/permissions';
import { ColumnDef } from '@tanstack/react-table';
import { useStore } from '../../store';

const getTypeStyles = (type: string) => {
    switch (type) {
        case 'Matériel':
            return {
                icon: HardDrive,
                color: 'text-muted-foreground',
                bg: 'bg-muted/30',
                border: 'border-muted',
                badge: 'bg-muted text-muted-foreground border-muted'
            };
        case 'Logiciel':
            return {
                icon: Cpu,
                color: 'text-primary',
                bg: 'bg-primary/10',
                border: 'border-primary/20',
                badge: 'bg-primary/10 text-primary border-primary/20'
            };
        case 'Données':
            return {
                icon: Database,
                color: 'text-purple-600 dark:text-purple-400',
                bg: 'bg-purple-100/50 dark:bg-purple-900/20',
                border: 'border-purple-200 dark:border-purple-800/50',
                badge: 'bg-purple-50 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400 border-purple-100 dark:border-purple-800'
            };
        case 'Service':
            return {
                icon: Activity,
                color: 'text-success',
                bg: 'bg-success/10',
                border: 'border-success/20',
                badge: 'bg-success/10 text-success border-success/20'
            };
        case 'Humain':
            return {
                icon: Users,
                color: 'text-warning',
                bg: 'bg-warning/10',
                border: 'border-warning/20',
                badge: 'bg-warning/10 text-warning border-warning/20'
            };
        default:
            return {
                icon: Server,
                color: 'text-muted-foreground',
                bg: 'bg-muted/30',
                border: 'border-muted',
                badge: 'bg-muted text-muted-foreground border-muted'
            };
    }
};

interface AssetListProps {
    assets: Asset[];
    loading: boolean;
    viewMode: 'grid' | 'list' | 'matrix' | 'kanban';
    user: UserProfile | null;
    onEdit: (asset: Asset) => void;
    onDelete: (id: string, name: string) => void;
    onDuplicate?: (asset: Asset) => void;
    onGenerateLabel: (asset: Asset) => void;
    isGeneratingLabels?: boolean;
    canEdit: boolean;
    activeFiltersQuery?: string;
    onBulkDelete?: (ids: string[]) => void;
    users?: UserProfile[];
    duplicatingIds?: Set<string>;
}

const getCriticalityColor = (level: Criticality) => {
    switch (level) {
        case Criticality.CRITICAL: return 'bg-error-bg text-error-text border-error-border/50';
        case Criticality.HIGH: return 'bg-warning-bg text-warning-text border-warning-border/50';
        case Criticality.MEDIUM: return 'bg-warning/10 text-warning border-warning/20';
        default: return 'bg-success-bg text-success-text border-success-border/50';
    }
};

export const AssetList = React.memo<AssetListProps>(({
    assets,
    loading,
    viewMode,
    user,
    onEdit,
    onDelete,
    onDuplicate,
    onBulkDelete,
    activeFiltersQuery,
    canEdit,
    onGenerateLabel,
    isGeneratingLabels,
    users,
    duplicatingIds = new Set(),
}) => {
    const { t } = useStore();
    const canDelete = canDeleteResource(user, 'Asset');

    const filteredAssets = useMemo(() => {
        if (!activeFiltersQuery) return assets;
        return assets.filter(asset =>
            asset.name.toLowerCase().includes(activeFiltersQuery.toLowerCase()) ||
            asset.type.toLowerCase().includes(activeFiltersQuery.toLowerCase()) ||
            asset.owner?.toLowerCase().includes(activeFiltersQuery.toLowerCase())
        );
    }, [assets, activeFiltersQuery]);

    const columns = useMemo<ColumnDef<Asset>[]>(() => [
        {
            header: t('common.name'),
            accessorKey: 'name',
            cell: ({ row }) => <span className="font-bold text-foreground">{row.original.name}</span>,
            meta: { className: 'w-full md:w-auto' }
        },
        {
            header: t('common.type'),
            accessorKey: 'type',
            meta: { className: 'hidden md:table-cell' },
            cell: ({ row }) => {
                const styles = getTypeStyles(row.original.type);
                const TypeIcon = styles.icon;
                return (
                    <div className="flex items-center gap-2">
                        <div className={`p-1.5 rounded-lg ${styles.bg} ${styles.color} border ${styles.border}`}>
                            <TypeIcon className="h-3.5 w-3.5" />
                        </div>
                        <span className={`px-2 py-0.5 rounded-md text-[11px] font-bold border shadow-sm ${styles.badge}`}>
                            {row.original.type}
                        </span>
                    </div>
                );
            }
        },
        {
            header: t('common.criticality'),
            accessorKey: 'confidentiality',
            cell: ({ row }) => <span className={`px-2 py-1 rounded-lg text-[11px] font-bold uppercase tracking-wider border shadow-sm ${getCriticalityColor(row.original.confidentiality)}`}>{row.original.confidentiality}</span>
        },
        {
            header: t('common.owner'),
            accessorKey: 'owner',
            meta: { className: 'hidden lg:table-cell' },
            cell: ({ row }) => {
                const ownerName = row.original.owner;
                const ownerUser = users?.find(u => u.displayName === ownerName || u.email === ownerName);
                return (
                    <div className="flex items-center gap-2">
                        <img
                            src={getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role)}
                            alt=""
                            className="w-6 h-6 rounded-full border border-muted object-cover bg-muted/30"
                            onError={(e) => {
                                const target = e.target as HTMLImageElement;
                                target.src = getUserAvatarUrl(null, ownerUser?.role);
                            }}
                        />
                        <span className="font-medium text-foreground">{ownerName}</span>
                    </div>
                );
            }
        },
        {
            header: t('common.status'),
            accessorKey: 'lifecycleStatus',
            meta: { className: 'hidden xl:table-cell' },
            cell: ({ row }) => (
                <div className="flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${row.original.lifecycleStatus === 'En service' ? 'bg-success' : 'bg-muted'}`}></span>
                    <span>
                        {(() => {
                            const val = row.original.lifecycleStatus || 'Neuf';
                            if (val === 'Neuf') return t('assets.status.new');
                            if (val === 'En service') return t('assets.status.inService');
                            return val;
                        })()}
                    </span>
                </div>
            )
        },
        {
            header: t('common.actions.title'),
            id: 'actions',
            cell: ({ row }) => {
                const isDuplicating = duplicatingIds.has(row.original.id);
                const menuItems: RowActionItem[] = [
                    {
                        label: t('assets.printLabel'),
                        icon: Tag,
                        onClick: () => onGenerateLabel(row.original),
                        disabled: isGeneratingLabels,
                    },
                    ...(canEdit ? [{
                        label: t('assets.editAsset'),
                        icon: Edit,
                        onClick: () => onEdit(row.original),
                    }] : []),
                    ...(onDuplicate && canEdit ? [{
                        label: t('common.duplicate') || 'Dupliquer',
                        icon: Copy,
                        onClick: () => onDuplicate(row.original),
                        disabled: isDuplicating,
                    }] : []),
                    ...(canDeleteResource(user, 'Asset') ? [{
                        label: t('assets.deleteAssetTooltip'),
                        icon: Trash2,
                        onClick: () => onDelete(row.original.id, row.original.name),
                        variant: 'danger' as const,
                    }] : []),
                ];

                if (menuItems.length === 0) return null;

                return (
                    <div className="flex justify-end">
                        <RowActionsMenu
                            items={menuItems}
                            aria-label={`Actions pour ${row.original.name}`}
                        />
                    </div>
                );
            }
        }
    ], [canEdit, isGeneratingLabels, onEdit, onDelete, onDuplicate, onGenerateLabel, user, t, users, duplicatingIds]);

    if (viewMode === 'list') {
        return (
            <div className="w-full max-w-full rounded-2xl overflow-hidden shadow-sm border border-slate-200 dark:border-white/5 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm">
                <DataTable
                    columns={columns}
                    data={assets}
                    selectable={canDelete}
                    onRowClick={(asset) => onEdit(asset)}
                    searchable={false}
                    exportable={false}
                    loading={loading}
                    pageSize={12}
                    onBulkDelete={onBulkDelete}
                    emptyState={
                        <EmptyState
                            icon={Server}
                            title={t('assets.emptyTitle')}
                            description={activeFiltersQuery ? t('assets.emptyDescSearch') : t('assets.emptyDesc')}
                            actionLabel={activeFiltersQuery || !canEdit ? undefined : t('assets.createAsset')}
                            onAction={activeFiltersQuery || !canEdit ? undefined : () => onEdit({} as Asset)}
                        />
                    }
                />
            </div>
        );
    }

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
            {loading ? (
                <div className="col-span-full"><CardSkeleton count={6} /></div>
            ) : filteredAssets.length === 0 ? (
                <div className="col-span-full">
                    <EmptyState
                        icon={Server}
                        title={t('assets.emptyTitle')}
                        description={activeFiltersQuery ? t('assets.emptyDescSearch') : t('assets.emptyDesc')}
                        actionLabel={activeFiltersQuery || !canEdit ? undefined : t('assets.createAsset')}
                        onAction={activeFiltersQuery || !canEdit ? undefined : () => onEdit({
                            id: '',
                            name: '',
                            type: 'Matériel',
                            lifecycleStatus: 'Opérationnel',
                            organizationId: user?.organizationId || '',
                            owner: user?.uid || '',
                            confidentiality: 'Moyen',
                            integrity: 'Moyen',
                            availability: 'Moyen',
                            location: '',
                            createdAt: new Date().toISOString(),
                            updatedAt: new Date().toISOString()
                        } as unknown as Asset)}
                    />
                </div>
            ) : (
                assets.map((asset) => {
                    const warrantyExpired = asset.warrantyEnd && new Date(asset.warrantyEnd) < new Date();
                    return (
                        <div
                            key={asset.id}
                            onClick={() => onEdit(asset)}
                            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onEdit(asset); }}
                            role="button"
                            tabIndex={0}
                            className="glass-panel p-4 sm:p-6 rounded-3xl shadow-sm card-hover cursor-pointer group flex flex-col border border-muted/50 dark:border-white/5 transition-all relative overflow-hidden focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50"
                        >
                            <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-transparent dark:from-white/5 pointer-events-none" />
                            <div className="relative z-10 flex flex-col h-full">
                                <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-70 transition-opacity flex gap-2">
                                    <div className="flex gap-2">
                                        <Tooltip content={t('assets.printLabel')}>
                                            <button
                                                onClick={(e) => { e.stopPropagation(); onGenerateLabel(asset); }}
                                                className="p-2 bg-white/90 dark:bg-white/10 rounded-xl text-slate-500 dark:text-slate-300 hover:text-brand-600 shadow-sm backdrop-blur-sm transition-all hover:scale-110 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-brand-500"
                                                disabled={isGeneratingLabels}
                                            >
                                                <Tag className="h-4 w-4" />
                                            </button>
                                        </Tooltip>
                                        {canEdit && (
                                            <Tooltip content={t('assets.editAsset')}>
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); onEdit(asset); }}
                                                    className="p-2 bg-background/90 dark:bg-muted/10 rounded-xl text-muted-foreground hover:text-primary shadow-sm backdrop-blur-sm transition-all hover:scale-110 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50"
                                                >
                                                    <Edit className="h-4 w-4" />
                                                </button>
                                            </Tooltip>
                                        )}
                                        {canDeleteResource(user, 'Asset') && (
                                            <Tooltip content={t('assets.deleteAssetTooltip')}>
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); onDelete(asset.id, asset.name); }}
                                                    className="p-2 bg-background/90 dark:bg-muted/10 rounded-xl text-muted-foreground hover:text-destructive shadow-sm backdrop-blur-sm transition-all hover:scale-110 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50"
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </button>
                                            </Tooltip>
                                        )}
                                    </div>
                                </div>
                                <div className="flex justify-between items-start mb-4">
                                    <div className={`p-3 rounded-2xl border shadow-sm transition-transform group-hover:scale-110 duration-300 ${getTypeStyles(asset.type).bg} ${getTypeStyles(asset.type).color} ${getTypeStyles(asset.type).border}`}>
                                        {React.createElement(getTypeStyles(asset.type).icon, { className: "h-6 w-6" })}
                                    </div>
                                    <div className="flex gap-2">
                                        <span className={`px-2 py-1 rounded-lg text-[11px] font-bold uppercase tracking-wider border shadow-sm ${getCriticalityColor(asset.confidentiality)}`}>{asset.confidentiality}</span>
                                    </div>
                                </div>
                                <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-1 leading-tight">{asset.name}</h3>
                                <div className="flex items-center gap-2 mb-4">
                                    <span className={`text-[11px] font-bold px-2 py-0.5 rounded-md border shadow-sm ${getTypeStyles(asset.type).badge}`}>{asset.type}</span>
                                    <span className="text-muted-foreground/50">•</span>
                                    <div className="flex items-center gap-1.5">
                                        <img
                                            src={getUserAvatarUrl(users?.find(u => u.displayName === asset.owner || u.email === asset.owner)?.photoURL, users?.find(u => u.displayName === asset.owner || u.email === asset.owner)?.role)}
                                            alt=""
                                            className="w-4 h-4 rounded-full object-cover bg-slate-100 dark:bg-slate-800"
                                            onError={(e) => {
                                                const target = e.target as HTMLImageElement;
                                                target.src = getUserAvatarUrl(null, users?.find(u => u.displayName === asset.owner || u.email === asset.owner)?.role);
                                            }}
                                        />
                                        <span className="text-xs text-muted-foreground font-medium">{asset.owner}</span>
                                    </div>
                                </div>

                                <div className="mt-auto pt-4 border-t border-dashed border-slate-200 dark:border-white/10 flex justify-between items-center">
                                    <div className="flex items-center gap-2">
                                        <span className={`w-2 h-2 rounded-full ${asset.lifecycleStatus === 'En service' ? 'bg-success' : 'bg-muted'}`}></span>
                                        <span className="text-xs font-bold text-slate-600 dark:text-muted-foreground">
                                            {(() => {
                                                const val = asset.lifecycleStatus || 'Neuf';
                                                if (val === 'Neuf') return t('assets.status.new');
                                                if (val === 'En service') return t('assets.status.inService');
                                                return val;
                                            })()}
                                        </span>
                                    </div>
                                    {warrantyExpired && <span className="text-[11px] font-bold bg-error-bg text-error-text border border-error-border/50 px-2 py-1 rounded-lg shadow-sm">{t('assets.warrantyExp')}</span>}
                                </div>
                            </div>
                        </div>
                    );
                })
            )}
        </div >
    );
});
